import{c as e,Q as s,j as n,m as i}from"./chunks/framework.iD28w_5a.js";const c=JSON.parse('{"title":"VESA Framebuffer 调试","description":"","frontmatter":{"title":"VESA Framebuffer 调试"},"headers":[],"relativePath":"notes/001/note2_check_framebuffer.md","filePath":"notes/001/note2_check_framebuffer.md","lastUpdated":1779686691000}'),l={name:"notes/001/note2_check_framebuffer.md"};function r(t,a,p,o,d,h){return s(),n("div",null,[...a[0]||(a[0]=[i(`<p>下面给你整理一篇**“Bootloader + GDB 验证 VESA framebuffer”小博客**，可以直接放到你的技术博客里（偏实战向 + 踩坑总结风格）：</p><hr><h1 id="🧠-bootloader-图形模式调试实战-如何用-gdb-验证-vesa-framebuffer" tabindex="-1">🧠 Bootloader 图形模式调试实战：如何用 GDB 验证 VESA Framebuffer <a class="header-anchor" href="#🧠-bootloader-图形模式调试实战-如何用-gdb-验证-vesa-framebuffer" aria-label="Permalink to &quot;🧠 Bootloader 图形模式调试实战：如何用 GDB 验证 VESA Framebuffer&quot;">​</a></h1><p>在编写操作系统 bootloader 时，一个非常关键的步骤是：<strong>成功切换到 VESA 图形模式并正确使用 framebuffer</strong>。</p><p>但问题来了：</p><blockquote><p>👉 一旦进入图形模式，传统的 <code>printf</code> / BIOS 输出全都失效 👉 那我们该如何验证程序是否正确运行？</p></blockquote><p>本文记录一套<strong>在 GDB 中验证 framebuffer 的实战方法</strong>。</p><hr><h1 id="🚀-一、问题背景" tabindex="-1">🚀 一、问题背景 <a class="header-anchor" href="#🚀-一、问题背景" aria-label="Permalink to &quot;🚀 一、问题背景&quot;">​</a></h1><p>在 Stage2 Bootloader 中，我们完成了以下流程：</p><ul><li>获取 VESA 信息</li><li>获取 Mode 信息（例如 1024×768×32）</li><li>切换到 VESA 图形模式</li><li>获取 framebuffer 信息并保存到固定地址（如 <code>0x6400</code>）</li></ul><p>此时：</p><ul><li>屏幕进入图形模式（黑屏）</li><li>文本输出消失</li><li>无法通过传统方式调试</li></ul><p>👉 这时候必须借助 GDB。</p><hr><h1 id="🔍-二、在-gdb-中验证-framebuffer-信息" tabindex="-1">🔍 二、在 GDB 中验证 framebuffer 信息 <a class="header-anchor" href="#🔍-二、在-gdb-中验证-framebuffer-信息" aria-label="Permalink to &quot;🔍 二、在 GDB 中验证 framebuffer 信息&quot;">​</a></h1><p>首先检查我们保存的 framebuffer 信息：</p><div class="language-plaintext vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x/2gx 0x6400</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出类似：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0x6400: 0x00000000fd000000  0x0300040000000c00</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="📌-解析方式" tabindex="-1">📌 解析方式 <a class="header-anchor" href="#📌-解析方式" aria-label="Permalink to &quot;📌 解析方式&quot;">​</a></h2><h3 id="_1️⃣-framebuffer-地址-64-bit" tabindex="-1">1️⃣ Framebuffer 地址（64-bit） <a class="header-anchor" href="#_1️⃣-framebuffer-地址-64-bit" aria-label="Permalink to &quot;1️⃣ Framebuffer 地址（64-bit）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0xfd000000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 这是 framebuffer 的物理地址</p><hr><h3 id="_2️⃣-pitch-分辨率" tabindex="-1">2️⃣ Pitch + 分辨率 <a class="header-anchor" href="#_2️⃣-pitch-分辨率" aria-label="Permalink to &quot;2️⃣ Pitch + 分辨率&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pitch = 0x00000c00 = 3072</span></span>
<span class="line"><span>width  = 1024</span></span>
<span class="line"><span>height = 768</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>👉 验证方式：</p><ul><li><code>3072 / 1024 = 3</code></li><li>⇒ 每像素 3 字节</li></ul><p>👉 说明：<strong>RGB888（24-bit）格式</strong></p><hr><h1 id="🧪-三、核心验证方法-直接写-framebuffer" tabindex="-1">🧪 三、核心验证方法：直接写 framebuffer <a class="header-anchor" href="#🧪-三、核心验证方法-直接写-framebuffer" aria-label="Permalink to &quot;🧪 三、核心验证方法：直接写 framebuffer&quot;">​</a></h1><p>GDB 的最大优势是：</p><blockquote><p>👉 可以直接修改内存</p></blockquote><hr><h2 id="✅-方法一-写单个像素" tabindex="-1">✅ 方法一：写单个像素 <a class="header-anchor" href="#✅-方法一-写单个像素" aria-label="Permalink to &quot;✅ 方法一：写单个像素&quot;">​</a></h2><div class="language-plaintext vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set {int}0xfd000000 = 0x00FF0000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 在左上角写入一个红色像素</p><hr><h2 id="⚠️-问题" tabindex="-1">⚠️ 问题 <a class="header-anchor" href="#⚠️-问题" aria-label="Permalink to &quot;⚠️ 问题&quot;">​</a></h2><p>你可能会发现：</p><blockquote><p>❗ “看不太清”</p></blockquote><p>👉 原因：</p><ul><li>只写了一个像素</li><li>人眼难以察觉</li></ul><hr><h1 id="🟥-四、进阶验证-写一个色块" tabindex="-1">🟥 四、进阶验证：写一个色块 <a class="header-anchor" href="#🟥-四、进阶验证-写一个色块" aria-label="Permalink to &quot;🟥 四、进阶验证：写一个色块&quot;">​</a></h1><h2 id="方法-写一条红线" tabindex="-1">方法：写一条红线 <a class="header-anchor" href="#方法-写一条红线" aria-label="Permalink to &quot;方法：写一条红线&quot;">​</a></h2><div class="language-plaintext vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set $i = 0</span></span>
<span class="line"><span>while $i &lt; 200</span></span>
<span class="line"><span>  set {int}(0xfd000000 + $i*4) = 0x00FF0000</span></span>
<span class="line"><span>  set $i = $i + 1</span></span>
<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>👉 效果：</p><ul><li>屏幕出现一条红线</li><li>明显可见</li></ul><hr><h2 id="方法-画一个矩形-推荐" tabindex="-1">方法：画一个矩形（推荐） <a class="header-anchor" href="#方法-画一个矩形-推荐" aria-label="Permalink to &quot;方法：画一个矩形（推荐）&quot;">​</a></h2><div class="language-plaintext vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>set $y = 0</span></span>
<span class="line"><span>while $y &lt; 100</span></span>
<span class="line"><span>  set $x = 0</span></span>
<span class="line"><span>  while $x &lt; 100</span></span>
<span class="line"><span>    set {int}(0xfd000000 + ($y * 1024 + $x) * 4) = 0x00FF0000</span></span>
<span class="line"><span>    set $x = $x + 1</span></span>
<span class="line"><span>  end</span></span>
<span class="line"><span>  set $y = $y + 1</span></span>
<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>👉 效果：</p><p>✅ 左上角出现一个红色方块 👉 这是最直观的验证方式</p><hr><h1 id="⚠️-五、常见坑总结" tabindex="-1">⚠️ 五、常见坑总结 <a class="header-anchor" href="#⚠️-五、常见坑总结" aria-label="Permalink to &quot;⚠️ 五、常见坑总结&quot;">​</a></h1><h2 id="❌-坑-1-在实模式下直接写-framebuffer" tabindex="-1">❌ 坑 1：在实模式下直接写 framebuffer <a class="header-anchor" href="#❌-坑-1-在实模式下直接写-framebuffer" aria-label="Permalink to &quot;❌ 坑 1：在实模式下直接写 framebuffer&quot;">​</a></h2><p>如果仍在：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.code16</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 可能：</p><ul><li>访问失败</li><li>或行为不稳定</li></ul><hr><h2 id="❌-坑-2-误判色深" tabindex="-1">❌ 坑 2：误判色深 <a class="header-anchor" href="#❌-坑-2-误判色深" aria-label="Permalink to &quot;❌ 坑 2：误判色深&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pitch = 3072</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>很多人会误以为是 32-bit，但实际上：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3072 / 1024 = 3 bytes/pixel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 实际是：</p><p>👉 <strong>24-bit RGB888</strong></p><hr><h2 id="❌-坑-3-只写一个像素" tabindex="-1">❌ 坑 3：只写一个像素 <a class="header-anchor" href="#❌-坑-3-只写一个像素" aria-label="Permalink to &quot;❌ 坑 3：只写一个像素&quot;">​</a></h2><p>👉 肉眼不可见</p><p>✔ 必须写：</p><ul><li>一条线</li><li>或一个块</li></ul><hr><h1 id="🧩-六、调试建议-非常重要" tabindex="-1">🧩 六、调试建议（非常重要） <a class="header-anchor" href="#🧩-六、调试建议-非常重要" aria-label="Permalink to &quot;🧩 六、调试建议（非常重要）&quot;">​</a></h1><p>在 bootloader 阶段推荐使用：</p><h3 id="✔-gdb-能做的" tabindex="-1">✔ GDB 能做的 <a class="header-anchor" href="#✔-gdb-能做的" aria-label="Permalink to &quot;✔ GDB 能做的&quot;">​</a></h3><ul><li>查看 framebuffer 内存</li><li>修改 framebuffer</li><li>单步执行 VESA 代码</li><li>查看寄存器</li></ul><hr><h3 id="✔-不能依赖" tabindex="-1">✔ 不能依赖 <a class="header-anchor" href="#✔-不能依赖" aria-label="Permalink to &quot;✔ 不能依赖&quot;">​</a></h3><ul><li>printf</li><li>BIOS 输出</li><li>屏幕文本</li></ul><hr><h1 id="🎯-七、最佳实践总结" tabindex="-1">🎯 七、最佳实践总结 <a class="header-anchor" href="#🎯-七、最佳实践总结" aria-label="Permalink to &quot;🎯 七、最佳实践总结&quot;">​</a></h1><p>在 VESA 图形模式调试中：</p><blockquote><p>👉 <strong>“让 framebuffer 作为唯一输出设备”</strong></p></blockquote><hr><h2 id="推荐调试流程" tabindex="-1">推荐调试流程： <a class="header-anchor" href="#推荐调试流程" aria-label="Permalink to &quot;推荐调试流程：&quot;">​</a></h2><ol><li>获取 framebuffer 地址</li><li>用 GDB 查看结构</li><li>手动写入像素</li><li>在屏幕观察变化</li><li>逐步验证系统行为</li></ol><hr><h1 id="🚀-八、总结一句话" tabindex="-1">🚀 八、总结一句话 <a class="header-anchor" href="#🚀-八、总结一句话" aria-label="Permalink to &quot;🚀 八、总结一句话&quot;">​</a></h1><blockquote><p>👉 在没有文本输出的世界里， 👉 framebuffer 就是你的“调试打印函数”</p></blockquote><hr><p>如果你后面要做：</p><ul><li>简易 GUI</li><li>字体显示</li><li>窗口系统</li><li>UI 框架</li></ul><p>我可以帮你把这套 framebuffer 调试体系升级成：</p><p>👉 <strong>“最小图形内核渲染引擎”</strong></p><p>直接从 bootloader 进阶到图形系统 👀</p>`,99)])])}const u=e(l,[["render",r]]);export{c as __pageData,u as default};
